// Validate, Clean, and Check for Duplicates
const items = $input.all();
let runId = 0;
const BATCH_SIZE = parseInt($env.OLLAMA_BATCH_SIZE) || 5;

try {
  runId = $('Log Workflow Start').first().json.id;
} catch(e) { runId = 0; }

const cleaned = [];
const duplicateChecks = [];

for (const item of items) {
  const row = item.json;

  // Skip empty or too-short posts
  const postText = (row.post_text || '').toString().trim();
  if (postText.length < 20) continue;

  // Clean post text
  let cleanText = postText
    .replace(/&[a-z]+;/gi, ' ')
    .replace(/&#\d+;/g, ' ')
    .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

  if (cleanText.length > 2000) {
    cleanText = cleanText.substring(0, 1997) + '...';
  }

  let postDate;
  try {
    const parsed = new Date(row.post_date);
    if (isNaN(parsed.getTime())) throw new Error('Invalid');
    postDate = parsed.toISOString();
  } catch (e) {
    postDate = new Date().toISOString();
  }

  // Create a unique fingerprint for duplicate checking
  const source = (row.source || 'unknown').toString().trim();
  const author = (row.author || 'anonymous').toString().trim();

  cleaned.push({
    json: {
      source: source,
      group_name: (row.group_name || '').toString().trim(),
      author: author,
      post_date: postDate,
      post_text: cleanText,
      comments: (row.comments || '').toString().trim(),
      run_id: runId,
      _check_duplicate: true,
      _original_index: cleaned.length
    }
  });

  // Prepare duplicate check query params
  duplicateChecks.push({
    source: source,
    author: author,
    post_date: postDate.split('T')[0]
  });
}

if (cleaned.length === 0) {
  return [{ json: { _empty: true, run_id: runId } }];
}

// Store the items for the duplicate check node to process
return cleaned;

// Filter out items that already exist in database
const checkResults = $('Check Existing Posts').all();
const originalItems = $('Validate and Clean').all();

// Create a map of existing posts using source+author+date as key
const existingMap = new Map();
for (const result of checkResults) {
  if (result.json && result.json.source) {
    const key = `${result.json.source}|${result.json.author}|${result.json.post_date}`;
    existingMap.set(key, true);
  }
}

// Filter original items
const newItems = [];
for (const item of originalItems) {
  const key = `${item.json.source}|${item.json.author}|${item.json.post_date.split('T')[0]}`;
  if (!existingMap.has(key) && !item.json._skip) {
    newItems.push(item);
  }
}

if (newItems.length === 0) {
  return [{ json: { _empty: true, run_id: originalItems[0]?.json.run_id || 0 } }];
}

return newItems;

