return { json: input };

// Parse Ollama Response with Confidence Scoring
const input = $input.first().json;
const prevData = $('Format Ollama Prompt').first().json;

let parsed = null;
const responseText = input.response || '';
let confidenceScore = 1.0;
const missingFields = [];

// Try to parse JSON
try {
  parsed = JSON.parse(responseText);
} catch (e) {
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      parsed = JSON.parse(jsonMatch[0]);
      confidenceScore -= 0.2; // Had to extract from text
    } catch (e2) {
      parsed = null;
      confidenceScore = 0;
    }
  } else {
    confidenceScore = 0;
  }
}

// Validation arrays
const validCategories = ['Pain Point', 'Service Request', 'Recommendation Needed', 'General Discussion'];
const validSentiments = ['Positive', 'Negative', 'Frustrated', 'Neutral'];
const validRelevance = ['High', 'Medium', 'Low'];

// Build result with defaults and track confidence
let result = {
  source: prevData.source,
  group_name: prevData.group_name,
  author: prevData.author,
  post_date: prevData.post_date,
  post_text: prevData.post_text,
  comments: prevData.comments,
  run_id: prevData.run_id,
  retry_count: prevData.retry_count,
  summary: '',
  category: 'General Discussion',
  themes: [],
  sentiment: 'Neutral',
  business_relevance: 'Low',
  marketing_angle: null,
  pain_points: [],
  analysis_confidence: confidenceScore,
  _parse_error: false
};

if (!parsed) {
  result.summary = 'Analysis failed - could not parse LLM response';
  result._parse_error = true;
  result.analysis_confidence = 0;
} else {
  // Check each field and adjust confidence
  if (!parsed.summary) missingFields.push('summary');
  else result.summary = parsed.summary.toString().substring(0, 1000);

  if (!parsed.category || !validCategories.includes(parsed.category)) {
    missingFields.push('category');
    confidenceScore -= 0.15;
  } else {
    result.category = parsed.category;
  }

  if (!Array.isArray(parsed.themes) || parsed.themes.length === 0) {
    missingFields.push('themes');
    confidenceScore -= 0.1;
  } else {
    result.themes = parsed.themes.slice(0, 10);
  }

  if (!parsed.sentiment || !validSentiments.includes(parsed.sentiment)) {
    missingFields.push('sentiment');
    confidenceScore -= 0.1;
  } else {
    result.sentiment = parsed.sentiment;
  }

  if (!parsed.business_relevance || !validRelevance.includes(parsed.business_relevance)) {
    missingFields.push('business_relevance');
    confidenceScore -= 0.15;
  } else {
    result.business_relevance = parsed.business_relevance;
  }

  result.marketing_angle = parsed.marketing_angle || null;
  if (!parsed.marketing_angle) missingFields.push('marketing_angle');

  result.pain_points = Array.isArray(parsed.pain_points) ? parsed.pain_points.slice(0, 10) : [];
  if (!Array.isArray(parsed.pain_points) || parsed.pain_points.length === 0) {
    missingFields.push('pain_points');
  }

  // Final confidence calculation (can't go below 0)
  result.analysis_confidence = Math.max(0, confidenceScore);
  result._missing_fields = missingFields;
}

return { json: result };

// Build batched Slack notification
const items = $input.all();
const batchSize = items.length;

if (batchSize === 0) return [{ json: { _empty: true } }];

// Build blocks for each item
const blocks = [];
blocks.push({
  "type": "header",
  "text": {
    "type": "plain_text",
    "text": `📊 Intelligence Digest (${batchSize} new insights)`,
    "emoji": true
  }
});

for (const item of items) {
  const data = item.json;
  const emoji = data.business_relevance === 'High' ? '🔴' : '🟡';

  blocks.push({
    "type": "section",
    "text": {
      "type": "mrkdwn",
      "text": `${emoji} *${data.category}* (${data.business_relevance} relevance, ${Math.round(data.analysis_confidence * 100)}% confidence)\n> ${data.summary.substring(0, 200)}`
    }
  });

  blocks.push({
    "type": "context",
    "elements": [
      {
        "type": "mrkdwn",
        "text": `Source: ${data.source}/${data.group_name} | Themes: ${(data.themes || []).slice(0, 3).join(', ')}`
      }
    ]
  });
}

blocks.push({
  "type": "divider"
});

return {
  json: {
    blocks: blocks,
    count: batchSize
  }
};

// Batch complete - count processed
const runId = $('Log Workflow Start').first().json.id;
return { json: { run_id: runId } };

// Error Handler with detailed context
const error = $input.first();
const runId = $('Log Workflow Start').first()?.json?.id || 0;
const currentNode = error.pairedItem?.node || 'Unknown';
const batchInfo = $('Split Into Batches')?.first()?.json || {};

let errorMsg = '';
let rawPayload = {};
let itemPreview = '';

try {
  errorMsg = error.json?.message || error.json?.error || JSON.stringify(error.json || {});
  rawPayload = error.json || {};

  // Try to capture the post that caused the error
  if (error.json?.post_text) {
    itemPreview = error.json.post_text.substring(0, 100);
  }
} catch(e) {
  errorMsg = 'Unknown error';
}

return {
  json: {
    workflow_name: 'Intelligence Pipeline',
    run_id: runId,
    node_name: currentNode,
    batch_index: batchInfo.batchIndex || 0,
    item_preview: itemPreview,
    error_message: errorMsg.substring(0, 2000),
    raw_payload: rawPayload
  }
};
